import json
import hashlib
import hmac
import os
from flask import Flask, request, jsonify
from datetime import datetime

app = Flask(__name__)

# Configuration
WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET')
ALLOWED_PARTNERS = os.environ.get('ALLOWED_PARTNERS', '').split(',')

def validate_signature(request, secret):
    """Validate the webhook signature"""
    signature = request.headers.get('X-Signature')
    if not signature:
        return False
    
    payload = request.get_data()
    expected_signature = hmac.new(
        secret.encode('utf-8'),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_partner(partner_id):
    """Validate if partner is allowed"""
    return partner_id in ALLOWED_PARTNERS

@app.route('/webhook/payment', methods=['POST'])
def payment_webhook():
    try:
        # Validate signature
        if not validate_signature(request, WEBHOOK_SECRET):
            return jsonify({'error': 'Invalid signature'}), 401
        
        # Get partner ID from headers
        partner_id = request.headers.get('X-Partner-ID')
        if not partner_id:
            return jsonify({'error': 'Missing partner ID'}), 400
        
        # Validate partner
        if not validate_partner(partner_id):
            return jsonify({'error': 'Unauthorized partner'}), 403
        
        # Parse payload
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON payload'}), 400
        
        # Process payment webhook
        event_type = data.get('event_type')
        payment_id = data.get('payment_id')
        amount = data.get('amount')
        status = data.get('status')
        
        # Log the event
        timestamp = datetime.utcnow().isoformat()
        print(f"Payment webhook received - Partner: {partner_id}, Event: {event_type}, Payment: {payment_id}, Status: {status}")
        
        # Here you would process the payment event
        # For example: update database, send notifications, etc.
        
        return jsonify({
            'status': 'success',
            'message': 'Webhook processed successfully',
            'timestamp': timestamp
        }), 200
        
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=int(os.environ.get('PORT', 8080)))